import React, { useState, useEffect, useCallback } from 'react';
import Layout from '../components/shared/Layout';
import { StripeCardForm, ChargeModal } from '../components/billing/StripePayment';
import { PlatformIcons, PLATFORMS, formatKPI } from '../utils/platforms';
import api from '../utils/api';

const BRAND_GRADIENTS = {
  visa:       'linear-gradient(135deg,#1a1f71,#2563eb)',
  mastercard: 'linear-gradient(135deg,#eb001b,#f79e1b)',
  amex:       'linear-gradient(135deg,#2e77bc,#0a3d7c)',
  discover:   'linear-gradient(135deg,#f76f20,#e44a00)',
  unknown:    'linear-gradient(135deg,#7c3aed,#a855f7)',
};

function PaymentCard({ method, onSetDefault, onDelete, isDefault }) {
  const gradient = BRAND_GRADIENTS[method.brand?.toLowerCase()] || BRAND_GRADIENTS.unknown;
  const now = new Date();
  const isExpired = method.expYear && (
    method.expYear < now.getFullYear() ||
    (method.expYear === now.getFullYear() && method.expMonth < now.getMonth() + 1)
  );

  return (
    <div style={{ borderRadius:16, overflow:'hidden', border:`2px solid ${isDefault?'var(--purple-primary)':isExpired?'rgba(239,68,68,0.4)':'var(--border-subtle)'}`, background:'var(--bg-card)', boxShadow:isDefault?'0 0 0 1px rgba(124,58,237,0.2),0 8px 24px rgba(124,58,237,0.12)':'var(--shadow-card)', transition:'all 0.2s' }}>
      {/* Card visual */}
      <div style={{ padding:'20px 22px', background:gradient, minHeight:120, position:'relative' }}>
        {isDefault && <div style={{ position:'absolute', top:12, right:12, background:'rgba(255,255,255,0.2)', backdropFilter:'blur(8px)', padding:'3px 10px', borderRadius:20, fontSize:10, fontWeight:700, color:'white' }}>DEFAULT</div>}
        {isExpired && <div style={{ position:'absolute', top:12, right:12, background:'rgba(239,68,68,0.8)', padding:'3px 10px', borderRadius:20, fontSize:10, fontWeight:700, color:'white' }}>EXPIRED</div>}
        <div style={{ fontSize:22, marginBottom:14 }}>💳</div>
        <div style={{ fontSize:16, fontWeight:700, color:'rgba(255,255,255,0.55)', letterSpacing:4, marginBottom:10, fontFamily:'DM Mono,monospace' }}>
          •••• •••• •••• {method.last4}
        </div>
        <div style={{ display:'flex', justifyContent:'space-between' }}>
          <div>
            <div style={{ fontSize:10, color:'rgba(255,255,255,0.5)', textTransform:'uppercase', marginBottom:2 }}>Holder</div>
            <div style={{ fontSize:12, fontWeight:600, color:'white' }}>{method.holderName || 'Card Holder'}</div>
          </div>
          <div style={{ textAlign:'right' }}>
            <div style={{ fontSize:10, color:'rgba(255,255,255,0.5)', textTransform:'uppercase', marginBottom:2 }}>Expires</div>
            <div style={{ fontSize:12, fontWeight:600, color:isExpired?'#fca5a5':'white' }}>
              {String(method.expMonth).padStart(2,'0')}/{String(method.expYear).slice(-2)}
            </div>
          </div>
        </div>
      </div>
      {/* Actions */}
      <div style={{ padding:'14px 16px', display:'flex', gap:8, alignItems:'center', flexWrap:'wrap' }}>
        {method.nickname && <div style={{ flex:1, fontSize:12, fontWeight:600, color:'var(--text-muted)' }}>"{method.nickname}"</div>}
        {!isDefault && !isExpired && (
          <button onClick={() => onSetDefault(method._id)}
            style={{ padding:'5px 12px', borderRadius:8, border:'1px solid var(--border-subtle)', background:'var(--bg-elevated)', color:'var(--text-muted)', cursor:'pointer', fontSize:11, fontWeight:600 }}>
            Set Default
          </button>
        )}
        <button onClick={() => onDelete(method._id, method)}
          style={{ padding:'5px 10px', borderRadius:8, border:'1px solid rgba(239,68,68,0.3)', background:'rgba(239,68,68,0.08)', color:'#ef4444', cursor:'pointer', fontSize:11, fontWeight:600 }}>
          Remove
        </button>
      </div>
    </div>
  );
}

export default function AdSpendPage() {
  const [activeTab,    setActiveTab]    = useState('overview');
  const [invoices,     setInvoices]     = useState([]);
  const [payMethods,   setPayMethods]   = useState([]);
  const [loading,      setLoading]      = useState(true);
  const [showAddCard,  setShowAddCard]  = useState(false);
  const [showCharge,   setShowCharge]   = useState(null);
  const [generating,   setGenerating]   = useState(false);
  const [toast,        setToast]        = useState('');

  const showToast = msg => { setToast(msg); setTimeout(() => setToast(''), 5000); };

  const fetchData = useCallback(async () => {
    try {
      const [invRes, pmRes] = await Promise.all([
        api.get('/stripe/invoices'),
        api.get('/stripe/payment-methods')
      ]);
      setInvoices(invRes.data.invoices || []);
      setPayMethods(pmRes.data || []);
    } catch {} finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleSetDefault = async (id) => {
    await api.patch(`/stripe/payment-methods/${id}/set-default`);
    setPayMethods(ms => ms.map(m => ({ ...m, isDefault: m._id === id })));
    showToast('✅ Default payment method updated');
  };

  const handleDelete = async (id, method) => {
    const label = `${method.brand} ****${method.last4}`;
    if (!window.confirm(`Remove ${label}?`)) return;
    await api.delete(`/stripe/payment-methods/${id}`);
    setPayMethods(ms => ms.filter(m => m._id !== id));
    showToast('Payment method removed');
  };

  const handleGenerateInvoices = async () => {
    setGenerating(true);
    try {
      const res = await api.post('/invoices/generate', {
        period: { start: new Date(Date.now()-30*86400000).toISOString(), end: new Date().toISOString() }
      });
      showToast(`✅ ${res.data.created} invoice${res.data.created!==1?'s':''} generated`);
      fetchData();
    } catch (err) { showToast('❌ '+err.message); }
    finally { setGenerating(false); }
  };

  // Download invoice as text file
  const downloadInvoice = (invoice) => {
    const content = [
      'ADSPULSE — INVOICE',
      '==================',
      `Invoice #:  ${invoice.invoiceNumber}`,
      `Date:       ${new Date(invoice.createdAt).toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'})}`,
      `Platform:   ${PLATFORMS.find(p=>p.id===invoice.platform)?.name||invoice.platform||'General'}`,
      `Status:     ${invoice.status?.toUpperCase()}`,
      `Payment:    ${invoice.paymentMethod||'N/A'}`,
      `Amount:     $${invoice.amount?.toFixed(2)} ${invoice.currency||'USD'}`,
      '',
      ...(invoice.lines||[]).map(l=>`  · ${l.description||'Ad Spend'}: $${(l.amount||0).toFixed(2)}`),
      '',
      `Stripe ID:  ${invoice.stripePaymentIntentId||'N/A'}`,
      '==================',
    ].join('\n');
    const blob = new Blob([content], { type:'text/plain' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href = url; a.download = `invoice-${invoice.invoiceNumber}.txt`; a.click();
    URL.revokeObjectURL(url);
  };

  const totalSpent   = invoices.reduce((s,i) => s+(i.status==='paid'?i.amount:0), 0);
  const totalPending = invoices.reduce((s,i) => s+(i.status==='pending'?i.amount:0), 0);
  const defaultMethod = payMethods.find(m => m.isDefault);
  const stripeReady   = !!process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY;

  return (
    <Layout>
      {toast && (
        <div style={{ position:'fixed',top:20,right:20,zIndex:9999,padding:'13px 18px',borderRadius:12,background:'var(--bg-card)',border:'1px solid var(--border-subtle)',boxShadow:'0 8px 32px rgba(0,0,0,0.2)',fontSize:13,color:'var(--text-primary)',animation:'slideIn 0.3s ease-out',maxWidth:380 }}>
          {toast}
        </div>
      )}

      {/* Add Card Modal */}
      {showAddCard && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.65)',zIndex:2000,display:'flex',alignItems:'center',justifyContent:'center',padding:20 }}
          onClick={() => setShowAddCard(false)}>
          <div className="glass-card" style={{ padding:32,maxWidth:460,width:'100%' }} onClick={e=>e.stopPropagation()}>
            <StripeCardForm
              onSuccess={() => { fetchData(); showToast('✅ Card saved successfully!'); }}
              onClose={() => setShowAddCard(false)}
            />
          </div>
        </div>
      )}

      {/* Charge Modal */}
      {showCharge && (
        <ChargeModal
          amount={showCharge.amount}
          description={showCharge.description}
          platform={showCharge.platform}
          onSuccess={() => { fetchData(); showToast('✅ Payment successful!'); }}
          onClose={() => setShowCharge(null)}
        />
      )}

      <div className="page-header">
        <div>
          <h1 className="page-title">Ad Spend</h1>
          <p className="page-subtitle">Manage budgets, payment methods and invoices</p>
        </div>
        <div style={{ display:'flex',gap:10 }}>
          <button className="btn-secondary" onClick={handleGenerateInvoices} disabled={generating} style={{ fontSize:13 }}>
            {generating?'⏳ Generating...':'🧾 Generate Invoices'}
          </button>
          <button className="btn-primary" onClick={() => setShowAddCard(true)} style={{ fontSize:13 }}>
            + Add Card
          </button>
        </div>
      </div>

      {/* Summary */}
      <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))',gap:14,marginBottom:28 }}>
        {[
          { label:'Total Spent',    value:formatKPI(totalSpent,'currency'),   icon:'💸', color:'#ef4444' },
          { label:'Pending',        value:formatKPI(totalPending,'currency'), icon:'⏳', color:'#d97706' },
          { label:'Invoices',       value:invoices.length,                    icon:'🧾', color:'#3b82f6' },
          { label:'Payment Methods',value:payMethods.length,                  icon:'💳', color:'#7c3aed' },
        ].map(s => (
          <div key={s.label} className="glass-card" style={{ padding:'18px 20px' }}>
            <div style={{ fontSize:22,marginBottom:8 }}>{s.icon}</div>
            <div style={{ fontSize:22,fontWeight:800,color:s.color,marginBottom:4 }}>{s.value}</div>
            <div style={{ fontSize:12,color:'var(--text-muted)',fontWeight:600 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Stripe status */}
      {!stripeReady && (
        <div style={{ padding:'14px 20px',borderRadius:12,marginBottom:20,background:'rgba(217,119,6,0.07)',border:'1px solid rgba(217,119,6,0.2)',display:'flex',gap:12,alignItems:'flex-start' }}>
          <span style={{ fontSize:20,flexShrink:0 }}>⚙️</span>
          <div style={{ fontSize:13,color:'var(--text-muted)',lineHeight:1.7 }}>
            <strong style={{ color:'var(--text-primary)' }}>Stripe not configured.</strong> Add your keys to enable real payment processing:
            <br/>
            <code style={{ fontSize:11,background:'var(--bg-elevated)',padding:'2px 6px',borderRadius:4,display:'inline-block',marginTop:4 }}>client/.env.local → REACT_APP_STRIPE_PUBLISHABLE_KEY=pk_live_...</code>
            <br/>
            <code style={{ fontSize:11,background:'var(--bg-elevated)',padding:'2px 6px',borderRadius:4,display:'inline-block',marginTop:4 }}>server/.env → STRIPE_SECRET_KEY=sk_live_...</code>
          </div>
        </div>
      )}

      {/* Default payment banner */}
      {defaultMethod && (
        <div style={{ padding:'14px 20px',borderRadius:12,marginBottom:20,background:'rgba(124,58,237,0.07)',border:'1px solid rgba(124,58,237,0.2)',display:'flex',gap:14,alignItems:'center',flexWrap:'wrap' }}>
          <span style={{ fontSize:20 }}>💳</span>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:13,fontWeight:700,color:'var(--text-primary)' }}>Default Payment Method</div>
            <div style={{ fontSize:12,color:'var(--text-muted)' }}>
              {defaultMethod.brand?.toUpperCase()} ending in {defaultMethod.last4} · Expires {String(defaultMethod.expMonth).padStart(2,'0')}/{defaultMethod.expYear}
              {defaultMethod.nickname && ` · "${defaultMethod.nickname}"`}
            </div>
          </div>
          <button className="btn-secondary" style={{ fontSize:12 }}
            onClick={() => setShowCharge({ amount:50, description:'Ad spend top-up', platform:'general' })}>
            💸 Add Funds
          </button>
        </div>
      )}

      {!defaultMethod && !loading && (
        <div style={{ padding:'14px 20px',borderRadius:12,marginBottom:20,background:'rgba(239,68,68,0.08)',border:'1px solid rgba(239,68,68,0.3)',display:'flex',gap:14,alignItems:'center',flexWrap:'wrap' }}>
          <span style={{ fontSize:20 }}>⚠️</span>
          <div style={{ flex:1,fontSize:13,color:'#ef4444' }}>
            <strong>No payment method added.</strong> Add a card to fund campaigns and receive billing notifications.
          </div>
          <button className="btn-primary" onClick={() => setShowAddCard(true)} style={{ fontSize:12 }}>Add Card</button>
        </div>
      )}

      {/* Tabs */}
      <div style={{ display:'flex',gap:4,marginBottom:20,background:'var(--bg-elevated)',borderRadius:12,padding:4,width:'fit-content' }}>
        {[{id:'overview',label:'Overview'},{id:'payment-methods',label:'Payment Methods'},{id:'invoices',label:'Invoices'}].map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{
            padding:'8px 18px',borderRadius:9,border:'none',fontSize:13,fontWeight:600,cursor:'pointer',fontFamily:'DM Sans,sans-serif',
            background:activeTab===tab.id?'var(--bg-card)':'transparent',
            color:activeTab===tab.id?'var(--text-primary)':'var(--text-faint)',
            boxShadow:activeTab===tab.id?'0 2px 8px rgba(0,0,0,0.1)':'none',transition:'all 0.2s'
          }}>{tab.label}</button>
        ))}
      </div>

      {loading ? (
        <div style={{ display:'flex',flexDirection:'column',gap:12 }}>
          {[1,2,3].map(i => <div key={i} className="skeleton" style={{ height:80,borderRadius:12 }}/>)}
        </div>

      ) : activeTab === 'payment-methods' ? (
        <div>
          {payMethods.length === 0 ? (
            <div className="glass-card" style={{ padding:48,textAlign:'center' }}>
              <div style={{ fontSize:48,marginBottom:16 }}>💳</div>
              <h3 style={{ fontSize:18,fontWeight:700,color:'var(--text-primary)',margin:'0 0 8px' }}>No Payment Methods</h3>
              <p style={{ fontSize:13,color:'var(--text-muted)',margin:'0 0 24px' }}>
                {stripeReady ? 'Add a credit or debit card to fund your ad campaigns.' : 'Configure Stripe to enable payment processing.'}
              </p>
              <button className="btn-primary" onClick={() => setShowAddCard(true)}>+ Add Card</button>
            </div>
          ) : (
            <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:16 }}>
              {payMethods.map(m => (
                <PaymentCard key={m._id} method={m} isDefault={m.isDefault} onSetDefault={handleSetDefault} onDelete={handleDelete}/>
              ))}
              <div onClick={() => setShowAddCard(true)}
                style={{ borderRadius:16,border:'2px dashed var(--border-subtle)',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:40,cursor:'pointer',transition:'all 0.2s',minHeight:180 }}
                onMouseEnter={e => e.currentTarget.style.borderColor='var(--purple-primary)'}
                onMouseLeave={e => e.currentTarget.style.borderColor='var(--border-subtle)'}>
                <div style={{ fontSize:36,marginBottom:10 }}>+</div>
                <div style={{ fontSize:14,fontWeight:600,color:'var(--text-muted)' }}>Add Payment Card</div>
              </div>
            </div>
          )}
        </div>

      ) : activeTab === 'invoices' ? (
        <div className="glass-card" style={{ padding:24 }}>
          <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:20,flexWrap:'wrap',gap:10 }}>
            <h3 style={{ fontSize:16,fontWeight:700,color:'var(--text-primary)',margin:0 }}>
              Invoice History ({invoices.length})
            </h3>
            {invoices.length > 0 && (
              <button className="btn-secondary" style={{ fontSize:12 }}
                onClick={() => invoices.forEach(inv => setTimeout(() => downloadInvoice(inv), 100))}>
                📥 Download All
              </button>
            )}
          </div>
          {invoices.length === 0 ? (
            <div style={{ textAlign:'center',padding:'36px 20px',color:'var(--text-faint)' }}>
              <div style={{ fontSize:40,marginBottom:12 }}>🧾</div>
              <div style={{ fontWeight:600,marginBottom:8 }}>No invoices yet</div>
              <button className="btn-primary" onClick={handleGenerateInvoices} disabled={generating}>
                {generating?'⏳ Generating...':'🧾 Generate from Campaign Data'}
              </button>
            </div>
          ) : (
            <div className="responsive-table">
              <table style={{ width:'100%',borderCollapse:'collapse' }}>
                <thead>
                  <tr>
                    {['Invoice #','Platform','Amount','Status','Payment Method','Date',''].map(h => (
                      <th key={h} style={{ padding:'8px 14px',textAlign:'left',fontSize:11,color:'var(--text-faint)',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:'1px solid var(--border-subtle)',whiteSpace:'nowrap' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {invoices.map(inv => {
                    const Icon = PlatformIcons[inv.platform];
                    const pl   = PLATFORMS.find(p => p.id===inv.platform);
                    return (
                      <tr key={inv._id} style={{ borderBottom:'1px solid var(--border-subtle)' }}>
                        <td style={{ padding:'12px 14px',fontSize:12,fontWeight:700,color:'var(--text-primary)',fontFamily:'DM Mono,monospace' }}>{inv.invoiceNumber}</td>
                        <td style={{ padding:'12px 14px' }}>
                          <div style={{ display:'flex',alignItems:'center',gap:8 }}>
                            {Icon && <Icon size={16}/>}
                            <span style={{ fontSize:12,color:'var(--text-secondary)',fontWeight:600 }}>{pl?.name||inv.platform||'General'}</span>
                          </div>
                        </td>
                        <td style={{ padding:'12px 14px',fontSize:13,fontWeight:800,color:'var(--text-primary)' }}>${inv.amount?.toFixed(2)}</td>
                        <td style={{ padding:'12px 14px' }}>
                          <span className={`status-${inv.status==='paid'?'active':inv.status==='pending'?'paused':'draft'}`} style={{ fontSize:10 }}>
                            {inv.status?.toUpperCase()}
                          </span>
                        </td>
                        <td style={{ padding:'12px 14px',fontSize:12,color:'var(--text-muted)' }}>{inv.paymentMethod||'—'}</td>
                        <td style={{ padding:'12px 14px',fontSize:12,color:'var(--text-muted)',whiteSpace:'nowrap' }}>{new Date(inv.createdAt).toLocaleDateString()}</td>
                        <td style={{ padding:'12px 14px' }}>
                          <button onClick={() => downloadInvoice(inv)}
                            style={{ padding:'5px 12px',borderRadius:8,border:'1px solid var(--border-subtle)',background:'var(--bg-elevated)',color:'var(--text-muted)',cursor:'pointer',fontSize:11,fontWeight:600 }}>
                            📥
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>

      ) : (
        /* Overview */
        <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:16 }}>
          {PLATFORMS.map(pl => {
            const Icon   = PlatformIcons[pl.id];
            const plInvs = invoices.filter(i => i.platform===pl.id);
            const spent  = plInvs.reduce((s,i) => s+(i.status==='paid'?i.amount:0),0);
            if (!spent && !plInvs.length) return null;
            return (
              <div key={pl.id} className="glass-card" style={{ padding:22,border:`1px solid ${pl.color}33` }}>
                <div style={{ display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:14 }}>
                  <div style={{ display:'flex',alignItems:'center',gap:10 }}>
                    {Icon && <Icon size={26}/>}
                    <div style={{ fontWeight:700,fontSize:14,color:'var(--text-primary)' }}>{pl.name}</div>
                  </div>
                  <div style={{ fontSize:18,fontWeight:800,color:'#ef4444' }}>${spent.toFixed(0)}</div>
                </div>
                <div style={{ fontSize:12,color:'var(--text-faint)' }}>{plInvs.length} invoice{plInvs.length!==1?'s':''}</div>
              </div>
            );
          }).filter(Boolean)}
          {invoices.length === 0 && (
            <div className="glass-card" style={{ padding:48,textAlign:'center',gridColumn:'1/-1' }}>
              <div style={{ fontSize:48,marginBottom:16 }}>💳</div>
              <h3 style={{ fontSize:18,fontWeight:700,color:'var(--text-primary)',margin:'0 0 8px' }}>No Spend Data Yet</h3>
              <p style={{ fontSize:13,color:'var(--text-muted)',margin:'0 0 24px' }}>Generate invoices from campaign data or connect a platform.</p>
              <button className="btn-primary" onClick={handleGenerateInvoices} disabled={generating}>🧾 Generate from Campaign Data</button>
            </div>
          )}
        </div>
      )}
    </Layout>
  );
}
